export const sendEmergencyAlert = (userMessage) => {
  const contact = localStorage.getItem("emergencyContact");

  if (!contact) {
    console.warn("No emergency contact found");
    return;
  }

  const alertMessage = `
🚨 EMERGENCY ALERT 🚨
Your loved one may be in emotional distress.

Message detected:
"${userMessage}"

Please reach out immediately.
`;

  console.log("📞 Sending alert to:", contact);
  console.log(alertMessage);

  // 🔴 BACKEND READY (example)
  /*
  fetch("http://localhost:5000/send-alert", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      phone: contact,
      message: alertMessage,
    }),
  });
  */
};
